    15→// Package server provides an implementation of a streaming xDS server.
    16→package server
    17→
    18→import (
    19→	"context"
    20→
    21→	"google.golang.org/grpc/codes"
    22→	"google.golang.org/grpc/status"
    23→
    24→	"github.com/envoyproxy/go-control-plane/pkg/server/config"
    25→	"github.com/envoyproxy/go-control-plane/pkg/server/delta/v3"
    26→	"github.com/envoyproxy/go-control-plane/pkg/server/rest/v3"
    27→	"github.com/envoyproxy/go-control-plane/pkg/server/sotw/v3"
    28→	"github.com/envoyproxy/go-control-plane/pkg/server/stream/v3"
    29→
    30→	core "github.com/envoyproxy/go-control-plane/envoy/config/core/v3"
    31→	clusterservice "github.com/envoyproxy/go-control-plane/envoy/service/cluster/v3"
    32→	discovery "github.com/envoyproxy/go-control-plane/envoy/service/discovery/v3"
    33→	endpointservice "github.com/envoyproxy/go-control-plane/envoy/service/endpoint/v3"
    34→	extensionconfigservice "github.com/envoyproxy/go-control-plane/envoy/service/extension/v3"
    35→	listenerservice "github.com/envoyproxy/go-control-plane/envoy/service/listener/v3"
    36→	routeservice "github.com/envoyproxy/go-control-plane/envoy/service/route/v3"
    37→	runtimeservice "github.com/envoyproxy/go-control-plane/envoy/service/runtime/v3"
    38→	secretservice "github.com/envoyproxy/go-control-plane/envoy/service/secret/v3"
    39→	"github.com/envoyproxy/go-control-plane/pkg/cache/v3"
    40→	"github.com/envoyproxy/go-control-plane/pkg/resource/v3"
    41→	rlsconfigservice "github.com/envoyproxy/go-control-plane/ratelimit/service/ratelimit/v3"
    42→)
    43→
    44→// Server is a collection of handlers for streaming discovery requests.
    45→type Server interface {
    46→	endpointservice.EndpointDiscoveryServiceServer
    47→	clusterservice.ClusterDiscoveryServiceServer
    48→	routeservice.RouteDiscoveryServiceServer
    49→	routeservice.ScopedRoutesDiscoveryServiceServer
    50→	routeservice.VirtualHostDiscoveryServiceServer
    51→	listenerservice.ListenerDiscoveryServiceServer
    52→	discovery.AggregatedDiscoveryServiceServer
    53→	secretservice.SecretDiscoveryServiceServer
    54→	runtimeservice.RuntimeDiscoveryServiceServer
    55→	extensionconfigservice.ExtensionConfigDiscoveryServiceServer
    56→	rlsconfigservice.RateLimitConfigDiscoveryServiceServer
    57→
    58→	rest.Server
    59→	sotw.Server
    60→	delta.Server
    61→}
    62→
    63→// Callbacks is a collection of callbacks inserted into the server operation.
    64→// The callbacks are invoked synchronously.
    65→type Callbacks interface {
    66→	rest.Callbacks
    67→	sotw.Callbacks
    68→	delta.Callbacks
    69→}
    70→
    71→// CallbackFuncs is a convenience type for implementing the Callbacks interface.
    72→type CallbackFuncs struct {
    73→	StreamOpenFunc          func(context.Context, int64, string) error
    74→	StreamClosedFunc        func(int64, *core.Node)
    75→	DeltaStreamOpenFunc     func(context.Context, int64, string) error
    76→	DeltaStreamClosedFunc   func(int64, *core.Node)
    77→	StreamRequestFunc       func(int64, *discovery.DiscoveryRequest) error
    78→	StreamResponseFunc      func(context.Context, int64, *discovery.DiscoveryRequest, *discovery.DiscoveryResponse)
    79→	StreamDeltaRequestFunc  func(int64, *discovery.DeltaDiscoveryRequest) error
    80→	StreamDeltaResponseFunc func(int64, *discovery.DeltaDiscoveryRequest, *discovery.DeltaDiscoveryResponse)
    81→	FetchRequestFunc        func(context.Context, *discovery.DiscoveryRequest) error
    82→	FetchResponseFunc       func(*discovery.DiscoveryRequest, *discovery.DiscoveryResponse)
    83→}
    84→
    85→var _ Callbacks = CallbackFuncs{}
    86→
    87→// OnStreamOpen invokes StreamOpenFunc.
    88→func (c CallbackFuncs) OnStreamOpen(ctx context.Context, streamID int64, typeURL string) error {
    89→	if c.StreamOpenFunc != nil {
    90→		return c.StreamOpenFunc(ctx, streamID, typeURL)
    91→	}
    92→
    93→	return nil
    94→}
    95→
    96→// OnStreamClosed invokes StreamClosedFunc.
    97→func (c CallbackFuncs) OnStreamClosed(streamID int64, node *core.Node) {
    98→	if c.StreamClosedFunc != nil {
    99→		c.StreamClosedFunc(streamID, node)
   100→	}
   101→}
   102→
   103→// OnDeltaStreamOpen invokes DeltaStreamOpenFunc.
   104→func (c CallbackFuncs) OnDeltaStreamOpen(ctx context.Context, streamID int64, typeURL string) error {
   105→	if c.DeltaStreamOpenFunc != nil {
   106→		return c.DeltaStreamOpenFunc(ctx, streamID, typeURL)
   107→	}
   108→
   109→	return nil
   110→}
   111→
   112→// OnDeltaStreamClosed invokes DeltaStreamClosedFunc.
   113→func (c CallbackFuncs) OnDeltaStreamClosed(streamID int64, node *core.Node) {
   114→	if c.DeltaStreamClosedFunc != nil {
   115→		c.DeltaStreamClosedFunc(streamID, node)
   116→	}
   117→}
   118→
   119→// OnStreamRequest invokes StreamRequestFunc.
   120→func (c CallbackFuncs) OnStreamRequest(streamID int64, req *discovery.DiscoveryRequest) error {
   121→	if c.StreamRequestFunc != nil {
   122→		return c.StreamRequestFunc(streamID, req)
   123→	}
   124→
   125→	return nil
   126→}
   127→
   128→// OnStreamResponse invokes StreamResponseFunc.
   129→func (c CallbackFuncs) OnStreamResponse(ctx context.Context, streamID int64, req *discovery.DiscoveryRequest, resp *discovery.DiscoveryResponse) {
   130→	if c.StreamResponseFunc != nil {
   131→		c.StreamResponseFunc(ctx, streamID, req, resp)
   132→	}
   133→}
   134→
   135→// OnStreamDeltaRequest invokes StreamDeltaResponseFunc
   136→func (c CallbackFuncs) OnStreamDeltaRequest(streamID int64, req *discovery.DeltaDiscoveryRequest) error {
   137→	if c.StreamDeltaRequestFunc != nil {
   138→		return c.StreamDeltaRequestFunc(streamID, req)
   139→	}
   140→
   141→	return nil
   142→}
   143→
   144→// OnStreamDeltaResponse invokes StreamDeltaResponseFunc.
   145→func (c CallbackFuncs) OnStreamDeltaResponse(streamID int64, req *discovery.DeltaDiscoveryRequest, resp *discovery.DeltaDiscoveryResponse) {
   146→	if c.StreamDeltaResponseFunc != nil {
   147→		c.StreamDeltaResponseFunc(streamID, req, resp)
   148→	}
   149→}
   150→
   151→// OnFetchRequest invokes FetchRequestFunc.
   152→func (c CallbackFuncs) OnFetchRequest(ctx context.Context, req *discovery.DiscoveryRequest) error {
   153→	if c.FetchRequestFunc != nil {
   154→		return c.FetchRequestFunc(ctx, req)
   155→	}
   156→
   157→	return nil
   158→}
   159→
   160→// OnFetchResponse invoked FetchResponseFunc.
   161→func (c CallbackFuncs) OnFetchResponse(req *discovery.DiscoveryRequest, resp *discovery.DiscoveryResponse) {
   162→	if c.FetchResponseFunc != nil {
   163→		c.FetchResponseFunc(req, resp)
   164→	}
   165→}
   166→
   167→// NewServer creates handlers from a config watcher and callbacks.
   168→func NewServer(ctx context.Context, config cache.Cache, callbacks Callbacks, opts ...config.XDSOption) Server {
   169→	return NewServerAdvanced(rest.NewServer(config, callbacks),
   170→		sotw.NewServer(ctx, config, callbacks, opts...),
   171→		delta.NewServer(ctx, config, callbacks, opts...),
   172→	)
   173→}
   174→
   175→func NewServerAdvanced(restServer rest.Server, sotwServer sotw.Server, deltaServer delta.Server) Server {
   176→	return &server{rest: restServer, sotw: sotwServer, delta: deltaServer}
   177→}
   178→
   179→type server struct {
   180→	rest  rest.Server
   181→	sotw  sotw.Server
   182→	delta delta.Server
   183→}
   184→
   185→func (s *server) StreamHandler(stream stream.Stream, typeURL string) error {
   186→	return s.sotw.StreamHandler(stream, typeURL)
   187→}
   188→
   189→func (s *server) StreamAggregatedResources(stream discovery.AggregatedDiscoveryService_StreamAggregatedResourcesServer) error {
   190→	return s.StreamHandler(stream, resource.AnyType)
   191→}
   192→
   193→func (s *server) StreamEndpoints(stream endpointservice.EndpointDiscoveryService_StreamEndpointsServer) error {
   194→	return s.StreamHandler(stream, resource.EndpointType)
   195→}
   196→
   197→func (s *server) StreamClusters(stream clusterservice.ClusterDiscoveryService_StreamClustersServer) error {
   198→	return s.StreamHandler(stream, resource.ClusterType)
   199→}
   200→
   201→func (s *server) StreamRoutes(stream routeservice.RouteDiscoveryService_StreamRoutesServer) error {
   202→	return s.StreamHandler(stream, resource.RouteType)
   203→}
   204→
   205→func (s *server) StreamScopedRoutes(stream routeservice.ScopedRoutesDiscoveryService_StreamScopedRoutesServer) error {
   206→	return s.StreamHandler(stream, resource.ScopedRouteType)
   207→}
   208→
   209→func (s *server) StreamListeners(stream listenerservice.ListenerDiscoveryService_StreamListenersServer) error {
   210→	return s.StreamHandler(stream, resource.ListenerType)
   211→}
   212→
   213→func (s *server) StreamSecrets(stream secretservice.SecretDiscoveryService_StreamSecretsServer) error {
   214→	return s.StreamHandler(stream, resource.SecretType)
   215→}
   216→
   217→func (s *server) StreamRuntime(stream runtimeservice.RuntimeDiscoveryService_StreamRuntimeServer) error {
   218→	return s.StreamHandler(stream, resource.RuntimeType)
   219→}
   220→
   221→func (s *server) StreamExtensionConfigs(stream extensionconfigservice.ExtensionConfigDiscoveryService_StreamExtensionConfigsServer) error {
   222→	return s.StreamHandler(stream, resource.ExtensionConfigType)
   223→}
   224→
   225→func (s *server) StreamRlsConfigs(stream rlsconfigservice.RateLimitConfigDiscoveryService_StreamRlsConfigsServer) error {
   226→	return s.StreamHandler(stream, resource.RateLimitConfigType)
   227→}
   228→
   229→// VHDS doesn't support SOTW requests, so no handler for it exists.
   230→
   231→// Fetch is the universal fetch method.
   232→func (s *server) Fetch(ctx context.Context, req *discovery.DiscoveryRequest) (*discovery.DiscoveryResponse, error) {
   233→	return s.rest.Fetch(ctx, req)
   234→}
   235→
   236→func (s *server) FetchEndpoints(ctx context.Context, req *discovery.DiscoveryRequest) (*discovery.DiscoveryResponse, error) {
   237→	if req == nil {
   238→		return nil, status.Errorf(codes.Unavailable, "empty request")
   239→	}
   240→	req.TypeUrl = resource.EndpointType
   241→	return s.Fetch(ctx, req)
   242→}
   243→
   244→func (s *server) FetchClusters(ctx context.Context, req *discovery.DiscoveryRequest) (*discovery.DiscoveryResponse, error) {
   245→	if req == nil {
   246→		return nil, status.Errorf(codes.Unavailable, "empty request")
   247→	}
   248→	req.TypeUrl = resource.ClusterType
   249→	return s.Fetch(ctx, req)
   250→}

